#include<bits/stdc++.h>
using namespace std;
int qzh[10000010];
int main(void){
	int T;
	cin>>T;
	while(T--){
		string s;int q;
		cin>>s>>q;
		for(int i=1;i<=s.size();++i){
			qzh[i]=qzh[i-1];if(s[i-1]=='P')qzh[i]+=3;
			else if(s[i-1]=='p')qzh[i]+=2;
			else if(s[i-1]=='G')++qzh[i];
		}for(int i=1;i<=q;++i){
			int l,r;cin>>l>>r; 
			cout<<qzh[r]-qzh[l-1]<<'\n';
		}
	}
	return false;
}
